module RefModule(clk, reset, enable, count);input clk, reset, enable;
  output reg [3:0] count;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) begin
      count <= 4'b0;
    end
    else if (enable) begin
      count <= count + 1;
    end
  end

endmodule
